/**
 * mkraftman-windows-pc-keyboard v1.0.3
 * Uses sentinel character trick for reliable backspace on iOS/iPadOS.
 */
const SENTINEL = "\u200B";
class MkraftmanWindowsPCKeyboard extends HTMLElement {
  constructor() { super(); this.attachShadow({mode:"open"}); this._config=null; this._hass=null; this._built=false; this._savedScrollY=null; this._ignoreNext=false; }
  static getStubConfig() { return {}; }
  setConfig(c) { this._config=c||{}; if(this._hass&&!this._built) this._build(); }
  getCardSize(){return 1;} getGridOptions(){return{rows:1,columns:12,min_rows:1,min_columns:6};}
  set hass(h){this._hass=h;if(!this._config)return;if(!this._built)this._build();}
  _build(){if(this._built||!this._hass)return;const s=this.shadowRoot;s.innerHTML=`<style>:host{display:block;position:relative}.card{background:transparent;padding:8px 12px;box-sizing:border-box;display:flex;align-items:center;justify-content:center}.kb-btn{width:55px;height:55px;border-radius:0;border:none;background:transparent;color:#A9A9A9;cursor:pointer;display:flex;align-items:center;justify-content:center;padding:0;transition:opacity .15s;-webkit-tap-highlight-color:transparent}.kb-btn:active{opacity:.6}.kb-btn ha-icon{--mdc-icon-size:55px}.hidden-input{position:absolute;bottom:0;left:50%;width:1px;height:1px;opacity:0;border:none;outline:none;padding:0;margin:0;font-size:16px;color:transparent;caret-color:transparent;background:transparent;pointer-events:none;-webkit-appearance:none;-webkit-text-fill-color:transparent}</style><div class="card"><button class="kb-btn" id="k"><ha-icon icon="mdi:keyboard-outline"></ha-icon></button><input class="hidden-input" id="i" type="text" autocomplete="off" autocorrect="off" autocapitalize="off" spellcheck="false"/></div>`;const kb=s.getElementById("k"),inp=s.getElementById("i");kb.addEventListener("click",()=>{this._savedScrollY=null;this._ri(inp);inp.style.pointerEvents="auto";inp.focus();setTimeout(()=>{this.scrollIntoView({behavior:"smooth",block:"end"});setTimeout(()=>{this._savedScrollY=window.scrollY},500)},300)});inp.addEventListener("keydown",e=>{const k=e.key;if(k==="Enter"){this._sk("return");e.preventDefault();return}if(k==="Escape"){this._sk("escape");e.preventDefault();return}if(k==="Tab"){this._sk("tab");e.preventDefault();return}if(k==="ArrowLeft"){this._sk("left");e.preventDefault();return}if(k==="ArrowRight"){this._sk("right");e.preventDefault();return}if(k==="ArrowUp"){this._sk("up");e.preventDefault();return}if(k==="ArrowDown"){this._sk("down");e.preventDefault();return}if(k==="Backspace"){this._sk("back");e.preventDefault();this._ri(inp);return}});inp.addEventListener("input",()=>{if(this._ignoreNext){this._ignoreNext=false;return}const v=inp.value;if(v===""){this._sk("back")}else if(v.length>SENTINEL.length){const a=v.replace(SENTINEL,"");for(const c of a)this._sk(c===" "?"space":c)}this._ignoreNext=true;inp.value=SENTINEL;inp.setSelectionRange(SENTINEL.length,SENTINEL.length);if(this._savedScrollY!==null)requestAnimationFrame(()=>{window.scrollTo(0,this._savedScrollY)})});this._built=true}
  _ri(inp){this._ignoreNext=true;inp.value=SENTINEL;inp.setSelectionRange(SENTINEL.length,SENTINEL.length)}
  _sk(key){if(!this._hass)return;this._hass.callService("unified_remote","call",{remote_id:"Relmtech.Keyboard",action:"toggle",extras:{Values:[{Value:key}]}})}
  connectedCallback(){if(this._hass&&this._config&&!this._built)this._build()}
}
customElements.define("mkraftman-windows-pc-keyboard",MkraftmanWindowsPCKeyboard);
window.customCards=window.customCards||[];window.customCards.push({type:"mkraftman-windows-pc-keyboard",name:"Mkraftman Windows PC Keyboard",description:"Keyboard input for Windows PC via Unified Remote."});
